3	type Customer = { yearsWithMHPCO: number; previousContract: boolean };
4	type QuoteStep = { op: "quote"; items: { type: string; cursed?: boolean; enchantment?: number; material?: string }[] };
5	type Scenario = { customer: { yearsWithMHPCO: number; previousContract?: boolean }; steps: QuoteStep[] };
6	type QuoteResult = { premium: number };
7	
8	function readStdin(): Promise<string> {
9	  return new Promise((resolve) => {
10	    let buffer = "";
11	    process.stdin.on("data", (chunk) => {
12	      buffer += chunk;
13	    });
14	    process.stdin.on("end", () => resolve(buffer));
15	  });
16	}
17	
18	function normalizeCustomer(customer: Scenario["customer"]): Customer {
19	  return {
20	    yearsWithMHPCO: customer.yearsWithMHPCO,
21	    previousContract: customer.previousContract ?? false,
22	  };
23	}
24	
25	function runScenario(scenario: Scenario): { results: QuoteResult[] } {
26	  const customer = normalizeCustomer(scenario.customer);
27	  const results: QuoteResult[] = [];
28	  for (const step of scenario.steps) {
29	    if (step.op === "quote") {
30	      results.push({ premium: quote({ customer, items: step.items }) });
31	    }
32	  }
33	  return { results };
34	}
35	
36	async function main(): Promise<void> {
37	  const input = await readStdin();
38	  const scenario: Scenario = JSON.parse(input);
39	  const output = runScenario(scenario);
40	  process.stdout.write(JSON.stringify(output));
41	}
42	
43	main();
