15	export function quote(input: { customer: { yearsWithMHPCO: number; previousContract: boolean }; items: { type: string; cursed?: boolean; enchantment?: number }[] }): number {
16	  if (input.items.length === 0) return PROCESSING_FEE;
17	  const groups = new Map<string, { type: string; cursed?: boolean; enchantment?: number }[]>();
18	  for (const item of input.items) {
19	    if (BASE_PREMIUM_BY_TYPE[item.type] === undefined) {
20	      throw new Error(`Unknown item type: ${item.type}`);
21	    }
22	    const list = groups.get(item.type) ?? [];
23	    list.push(item);
24	    groups.set(item.type, list);
25	  }
26	  let policyBaseUnmodified = 0;
27	  let itemSurcharges = 0;
28	  let firstInsurance = 0;
29	  for (const [type, items] of groups) {
30	    const count = items.length;
31	    if (COMPONENT_TYPES.has(type) && count === 3) {
32	      policyBaseUnmodified += 60;
33	      firstInsurance += 60 * FIRST_INSURANCE_RATE;
34	    } else {
35	      for (const item of items) {
36	        const itemBase = BASE_PREMIUM_BY_TYPE[type];
37	        policyBaseUnmodified += itemBase;
38	        if (item.cursed) {
39	          itemSurcharges += itemBase * 0.5;
40	        }
41	        if ((item.enchantment ?? 0) >= 5) {
42	          itemSurcharges += itemBase * 0.3;
43	        }
44	        firstInsurance += itemBase * FIRST_INSURANCE_RATE;
45	      }
46	    }
47	  }
48	  let loyalty = 0;
49	  if (input.customer.yearsWithMHPCO >= 2) {
50	    loyalty = policyBaseUnmodified * 0.2;
51	  }
52	  let followUp = 0;
53	  if (input.customer.previousContract) {
54	    followUp = policyBaseUnmodified * 0.15;
55	  }
56	  return Math.ceil(policyBaseUnmodified + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
