function runScenario(scenario: Scenario): { results: StepResult[] } {
  const customer = normalizeCustomer(scenario.customer);
  const results: StepResult[] = [];
  const steps = scenario.steps;
  for (const step of steps) {
    if (step.op === "quote") {
      results.push({ premium: quote({ customer, items: step.items }) });
    } else if (step.op === "claim") {
      const referenced = steps[step.policy] as QuoteStep;
      const items = referenced.items;
      const remainingCap = policyCap(items);
      const { payout, remainingCap: newCap } = claim({ remainingCap, items }, step.incident);
      results.push({ payout, remainingCap: newCap });
    }
  }
  return { results };
}
